impl Default for RedactionConfig {
    fn default() -> Self {
        <kreuzberg::RedactionConfig as Default>::default().into()
    }
}

#[php_impl]
impl RedactionConfig {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(constructor)]
    pub fn new(categories: Vec<String>, strategy: String, preserveOffsets: bool) -> Self {
        Self {
            categories,
            strategy,
            ner: Default::default(),
            preserve_offsets: preserveOffsets,
            custom_terms: Default::default(),
            custom_patterns: Default::default(),
        }
    }

    pub fn get_categories(&self) -> Vec<String> {
        self.categories.clone()
    }

    pub fn get_strategy(&self) -> String {
        self.strategy.clone()
    }

    pub fn get_ner(&self) -> Option<NerConfig> {
        self.ner.clone().map(Into::into)
    }

    pub fn get_preserve_offsets(&self) -> bool {
        self.preserve_offsets.clone()
    }

    pub fn get_custom_terms(&self) -> Vec<RedactionTerm> {
        self.custom_terms.clone()
    }

    pub fn get_custom_patterns(&self) -> Vec<RedactionPattern> {
        self.custom_patterns.clone()
    }

    pub fn validate(&self) -> PhpResult<()> {
        let core_self = kreuzberg::RedactionConfig {
            categories: self
                .categories
                .clone()
                .into_iter()
                .map(|s| match s.as_str() {
                    "email" => kreuzberg::PiiCategory::Email,
                    "phone" => kreuzberg::PiiCategory::Phone,
                    "ssn" => kreuzberg::PiiCategory::Ssn,
                    "credit_card" => kreuzberg::PiiCategory::CreditCard,
                    "postal_code" => kreuzberg::PiiCategory::PostalCode,
                    "ip_address" => kreuzberg::PiiCategory::IpAddress,
                    "iban" => kreuzberg::PiiCategory::Iban,
                    "swift_bic" => kreuzberg::PiiCategory::SwiftBic,
                    "date_of_birth" => kreuzberg::PiiCategory::DateOfBirth,
                    "person" => kreuzberg::PiiCategory::Person,
                    "organization" => kreuzberg::PiiCategory::Organization,
                    "location" => kreuzberg::PiiCategory::Location,
                    "custom" => kreuzberg::PiiCategory::Custom(Default::default()),
                    _ => kreuzberg::PiiCategory::Email,
                })
                .collect(),
            strategy: match self.strategy.as_str() {
                "mask" => kreuzberg::RedactionStrategy::Mask,
                "hash" => kreuzberg::RedactionStrategy::Hash,
                "token_replace" => kreuzberg::RedactionStrategy::TokenReplace,
                "drop" => kreuzberg::RedactionStrategy::Drop,
                _ => Default::default(),
            },
            ner: self.ner.clone().map(Into::into),
            preserve_offsets: self.preserve_offsets,
            custom_terms: self.custom_terms.clone().into_iter().map(Into::into).collect(),
            custom_patterns: self.custom_patterns.clone().into_iter().map(Into::into).collect(),
        };
        let result = core_self
            .validate()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    #[allow(clippy::should_implement_trait)]
    #[php(name = "default")]
    pub fn default() -> RedactionConfig {
        kreuzberg::RedactionConfig::default().into()
    }
}

