#[derive(Clone)]
#[php_class]
#[php(name = "Kreuzberg\\LlmBackend")]
pub struct LlmBackend {
    inner: Arc<kreuzberg::LlmBackend>,
}

#[php_impl]
impl LlmBackend {
    pub fn detect(&self, text: String, categories: Vec<String>) -> PhpResult<Vec<Entity>> {
        let inner = self.inner.clone();
        let mut categories_core_result: Vec<kreuzberg::EntityCategory> = Vec::new();
        // `pname` here is `Vec<String>` from the PHP-facing signature (named enums are
        // surfaced as snake_case wire-strings via `<EnumName as From<String>>`). Iterating
        // a `Vec<String>` produces `&String`, so no hashtable-style `(key, value)`
        // destructure applies.
        for item in categories.iter() {
            categories_core_result.push(<kreuzberg::EntityCategory as From<String>>::from(item.clone()));
        }
        let categories_core: Vec<kreuzberg::EntityCategory> = categories_core_result;
        WORKER_RUNTIME.block_on(async {
            let result = inner
                .detect(&text, &categories_core[..])
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into_iter().map(Into::into).collect())
        })
    }

    pub fn detect_with_custom(
        &self,
        text: String,
        categories: Vec<String>,
        customLabels: Vec<String>,
    ) -> PhpResult<Vec<Entity>> {
        let inner = self.inner.clone();
        let mut categories_core_result: Vec<kreuzberg::EntityCategory> = Vec::new();
        // `pname` here is `Vec<String>` from the PHP-facing signature (named enums are
        // surfaced as snake_case wire-strings via `<EnumName as From<String>>`). Iterating
        // a `Vec<String>` produces `&String`, so no hashtable-style `(key, value)`
        // destructure applies.
        for item in categories.iter() {
            categories_core_result.push(<kreuzberg::EntityCategory as From<String>>::from(item.clone()));
        }
        let categories_core: Vec<kreuzberg::EntityCategory> = categories_core_result;
        WORKER_RUNTIME.block_on(async {
            let result = inner
                .detect_with_custom(&text, &categories_core[..], &customLabels[..])
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into_iter().map(Into::into).collect())
        })
    }
}

