#[serde(default, rename_all = "camelCase")]
pub struct DetectionResult {
    /// Page width in pixels (as seen by the model).
    #[php(prop, name = "pageWidth")]
    pub page_width: u32,
    /// Page height in pixels (as seen by the model).
    #[php(prop, name = "pageHeight")]
    pub page_height: u32,
    /// All layout detections on this page after postprocessing.
    pub detections: Vec<LayoutDetection>,
}

#[php_impl]
impl DetectionResult {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(constructor)]
    pub fn new(pageWidth: u32, pageHeight: u32) -> Self {
        Self {
            page_width: pageWidth,
            page_height: pageHeight,
            detections: Default::default(),
        }
    }

    pub fn get_page_width(&self) -> u32 {
        self.page_width.clone()
    }

    pub fn get_page_height(&self) -> u32 {
        self.page_height.clone()
    }

    pub fn get_detections(&self) -> Vec<LayoutDetection> {
        self.detections.clone()
    }
}

#[derive(Clone, serde::Serialize, serde::Deserialize, Default)]
#[php_class]
#[php(name = "Kreuzberg\\EmbeddedFile")]
#[serde(default, rename_all = "camelCase")]
pub struct EmbeddedFile {
    /// The filename as stored in the PDF name tree.
    #[php(prop, name = "name")]
    pub name: String,
    /// Raw file bytes from the embedded stream (already decompressed by lopdf).
    pub data: Vec<u8>,
    /// Compressed byte count of the original stream (before decompression).
    ///
    /// Used by callers to compute the decompression ratio and detect zip-bomb-style
    /// attacks that embed a tiny compressed stream expanding to gigabytes of data.
    #[php(prop, name = "compressedSize")]
    pub compressed_size: i64,
    /// MIME type if specified in the filespec, otherwise `None`.
    #[php(prop, name = "mimeType")]
    pub mime_type: Option<String>,
}

#[php_impl]
impl EmbeddedFile {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(constructor)]
    pub fn new(name: String, data: PhpBytes, compressedSize: i64, mimeType: Option<String>) -> Self {
        Self {
            name,
            data: data.0,
            compressed_size: compressedSize,
            mime_type: mimeType,
        }
    }

    pub fn get_name(&self) -> String {
        self.name.clone()
    }

    pub fn get_data(&self) -> Vec<u8> {
        self.data.clone()
    }

    pub fn get_compressed_size(&self) -> i64 {
        self.compressed_size.clone()
    }

    pub fn get_mime_type(&self) -> Option<String> {
        self.mime_type.clone()
    }
}

