    /**
     * Scan `text` for every PII category in `categories` and return all matches
     * in source-byte order.
     *
     * When `categories` is empty every supported regex-detectable category fires.
     * Person / Organization / Location are *not* covered by the pattern engine —
     * they must be supplied by a NER backend through the redaction engine.
     */
    #[php(name = "scanText")]
    pub fn scan_text(text: String, categories: Vec<String>) -> Vec<PatternMatch> {
        let mut categories_core_result: Vec<kreuzberg::PiiCategory> = Vec::new();
        // `pname` here is `Vec<String>` from the PHP-facing signature (named enums are
        // surfaced as snake_case wire-strings via `<EnumName as From<String>>`). Iterating
        // a `Vec<String>` produces `&String`, so no hashtable-style `(key, value)`
        // destructure applies.
        for item in categories.iter() {
            categories_core_result.push(<kreuzberg::PiiCategory as From<String>>::from(item.clone()));
        }
        let categories_core: Vec<kreuzberg::PiiCategory> = categories_core_result;
        kreuzberg::text::redaction::patterns::scan_text(&text, &categories_core[..])
            .into_iter()
            .map(Into::into)
            .collect()
    }

