    ::std::sync::Mutex::new(::std::option::Option::None);

unsafe extern "C" fn __ext_php_rs_module_startup(ty: i32, mod_num: i32) -> i32 {
    let startup = match __EXT_PHP_RS_MODULE_STARTUP.lock() {
        Ok(mut guard) => guard.take(),
        Err(_) => return 1,
    };
    match startup {
        Some(s) => match s.startup(ty, mod_num) {
            Ok(_) => 0,
            Err(_) => 1,
        },
        None => 1,
    }
}

